# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
from urllib.parse import urlparse
import boto3
import requests

def lambda_handler(event, context):
    viewer_request = event['Records'][0]['cf']['request']
    
    # Extract the URLs from the X-Enrich-URL header
    enrich_urls = viewer_request.get('headers', {}).get('x-enrich-url', [])
    enrich_urls = [url['value'] for url in enrich_urls]
    
    if not enrich_urls:
        return viewer_request
    
    # Initialize an empty dictionary to store enriched data
    enriched_data = {}
    
    # Fetch data from each URL and store it in the dictionary
    for url in enrich_urls:
        try:
            response = requests.get(url)
            if response.status_code == 200:
                enriched_data[urlparse(url).netloc] = response.json()
        except Exception as e:
            print(f"Error fetching {url}: {e}")
    
    # Add the enriched data to the viewer request headers
    viewer_request['headers']['x-enriched-data'] = [{'key': 'x-enriched-data', 'value': json.dumps(enriched_data), 'ttl': 0}]
    
    return viewer_request